import{c as t,Q as o,j as a,m as s}from"./chunks/framework.rlpw0eGz.js";const h=JSON.parse('{"title":"💿 Unattended Windows Installation Guide","description":"","frontmatter":{},"headers":[],"relativePath":"AUTOUNATTEND.md","filePath":"AUTOUNATTEND.md"}'),n={name:"AUTOUNATTEND.md"};function i(r,e,l,d,c,u){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="💿-unattended-windows-installation-guide" tabindex="-1">💿 Unattended Windows Installation Guide <a class="header-anchor" href="#💿-unattended-windows-installation-guide" aria-label="Permalink to &quot;💿 Unattended Windows Installation Guide&quot;">​</a></h1><p>The <code>autounattend.xml</code> file located in the root of this repository is a highly optimized configuration script designed to automate the installation of <strong>Windows 11 Pro</strong> (and Windows 10 Pro) from scratch, creating a streamlined, high-performance, and debloated baseline immediately upon first boot.</p><p><a href="https://github.com/YTxFSGAMERz/Windows-Optimisations/raw/master/autounattend.xml" class="md-button md-button--primary" target="_blank" rel="noreferrer">Download autounattend.xml</a></p><hr><h2 id="⚡-core-automation-features" tabindex="-1">⚡ Core Automation Features <a class="header-anchor" href="#⚡-core-automation-features" aria-label="Permalink to &quot;⚡ Core Automation Features&quot;">​</a></h2><h3 id="_1-hardware-restriction-bypasses" tabindex="-1">1. Hardware Restriction Bypasses <a class="header-anchor" href="#_1-hardware-restriction-bypasses" aria-label="Permalink to &quot;1. Hardware Restriction Bypasses&quot;">​</a></h3><p>Windows 11 has strict installation blocks for older processors or systems without modern hardware modules. This configuration automatically bypasses these checks:</p><ul><li><strong>TPM 2.0 Check</strong>: Bypassed (Bypasses <code>TPMCheck</code>).</li><li><strong>Secure Boot Check</strong>: Bypassed (Bypasses <code>SecureBootCheck</code>).</li><li><strong>RAM Capacity Check</strong>: Bypassed (Allows installation on systems with less than 4GB of RAM).</li><li><strong>Storage Capacity Check</strong>: Bypassed.</li></ul><h3 id="_2-automatic-system-tweaks-during-setup" tabindex="-1">2. Automatic System Tweaks during Setup <a class="header-anchor" href="#_2-automatic-system-tweaks-during-setup" aria-label="Permalink to &quot;2. Automatic System Tweaks during Setup&quot;">​</a></h3><p>The XML applies the following modifications directly into the registry during the OS installation process:</p><ul><li><strong>Windows Defender</strong>: Disabled system-wide via registry overrides.</li><li><strong>User Account Control (UAC)</strong>: Adjusted to the lowest level to prevent intrusive authorization popups.</li><li><strong>SmartScreen &amp; Core Isolation</strong>: Disabled to reduce real-time virtualization overhead.</li><li><strong>System Restore</strong>: Disabled to conserve disk space and write cycles.</li><li><strong>Fast Startup</strong>: Disabled to prevent persistent hibernation-related write bottlenecks.</li></ul><h3 id="_3-desktop-experience-custom-interface" tabindex="-1">3. Desktop Experience &amp; Custom Interface <a class="header-anchor" href="#_3-desktop-experience-custom-interface" aria-label="Permalink to &quot;3. Desktop Experience &amp; Custom Interface&quot;">​</a></h3><ul><li><strong>Classic Context Menu</strong>: Re-enables the classic right-click context menu (Windows 10 style) on Windows 11 by default.</li><li><strong>Taskbar Alignment</strong>: Left-aligned taskbar elements out-of-the-box.</li><li><strong>Taskbar Cleanups</strong>: Bing search results, widgets, and task view buttons are hidden.</li><li><strong>Desktop Icons</strong>: Restores classic system icons (&quot;This PC&quot;, &quot;Control Panel&quot;, &quot;Network&quot;, &quot;User Profile&quot;) directly to the desktop on first boot.</li></ul><h3 id="_4-deep-system-debloating" tabindex="-1">4. Deep System Debloating <a class="header-anchor" href="#_4-deep-system-debloating" aria-label="Permalink to &quot;4. Deep System Debloating&quot;">​</a></h3><p>The setup executes silent scripts to uninstall pre-loaded UWP applications, preventing them from consuming CPU and disk storage:</p><ul><li><em>Apps removed</em>: 3D Viewer, Weather, Solitaire Collection, Bing Search, Camera, Clipchamp, Alarms/Clock, Copilot, Cortana, Family Safety, Feedback Hub, Get Help, MSN News, Microsoft Photos, Power Automate, and various Xbox-related background integrations.</li></ul><h3 id="_5-automated-local-account-provisioning" tabindex="-1">5. Automated Local Account Provisioning <a class="header-anchor" href="#_5-automated-local-account-provisioning" aria-label="Permalink to &quot;5. Automated Local Account Provisioning&quot;">​</a></h3><ul><li><strong>Account Name</strong>: Creates a local offline user profile named <code>Admin</code>.</li><li><strong>Auto-Login</strong>: Configured to log in automatically to the desktop without prompts.</li><li><strong>Password</strong>: No password is set, and the password expiration policy is set to &quot;Never Expire&quot;.</li></ul><hr><h2 id="🛠️-step-by-step-installation-guide" tabindex="-1">🛠️ Step-by-Step Installation Guide <a class="header-anchor" href="#🛠️-step-by-step-installation-guide" aria-label="Permalink to &quot;🛠️ Step-by-Step Installation Guide&quot;">​</a></h2><p>To perform an automated, debloated installation using <code>autounattend.xml</code>, follow these steps:</p><h3 id="phase-1-prepare-the-installation-media" tabindex="-1">Phase 1: Prepare the Installation Media <a class="header-anchor" href="#phase-1-prepare-the-installation-media" aria-label="Permalink to &quot;Phase 1: Prepare the Installation Media&quot;">​</a></h3><ol><li><strong>Download Windows ISO</strong>: Download the official Windows 11 (or Windows 10) ISO directly from Microsoft&#39;s website.</li><li><strong>Launch Rufus</strong>: Open the <strong>Rufus</strong> utility (<code>Extra/rufus-3.22p.exe</code>) in this repository.</li><li><strong>Configure Rufus</strong>: <ul><li><strong>Device</strong>: Select your USB drive (minimum 8GB capacity).</li><li><strong>Boot Selection</strong>: Choose <strong>Disk or ISO image</strong> and click <strong>SELECT</strong> to load your downloaded Windows ISO.</li><li><strong>Partition Scheme</strong>: Select <strong>GPT</strong> (for UEFI systems) or <strong>MBR</strong> (for legacy BIOS systems).</li><li><strong>Target System</strong>: Select <strong>UEFI (non CSM)</strong>.</li></ul></li><li><strong>Create the Installer</strong>: Click <strong>START</strong>. A popup will appear. Ensure the standard Rufus hardware bypass options are unchecked (since our <code>autounattend.xml</code> already handles these and custom debloating much more aggressively). Click <strong>OK</strong> and wait for Rufus to complete writing.</li></ol><h3 id="phase-2-apply-the-automation-xml" tabindex="-1">Phase 2: Apply the Automation XML <a class="header-anchor" href="#phase-2-apply-the-automation-xml" aria-label="Permalink to &quot;Phase 2: Apply the Automation XML&quot;">​</a></h3><ol><li>Navigate to the root directory of this repository and copy the <code>autounattend.xml</code> file.</li><li>Open your written bootable USB drive in File Explorer.</li><li><strong>Paste at Root</strong>: Paste <code>autounattend.xml</code> directly into the <strong>root</strong> folder of your USB drive (alongside <code>setup.exe</code> and the <code>sources/</code> folder). <ul><li><em>Do NOT place it in any subfolders.</em></li></ul></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Your USB Drive (D:\\ or E:\\)</span></span>
<span class="line"><span>├── sources/</span></span>
<span class="line"><span>├── support/</span></span>
<span class="line"><span>├── efi/</span></span>
<span class="line"><span>├── autounattend.xml    &lt;-- MUST BE PLACED HERE!</span></span>
<span class="line"><span>├── bootmgr</span></span>
<span class="line"><span>└── setup.exe</span></span></code></pre></div><h3 id="phase-3-perform-the-installation" tabindex="-1">Phase 3: Perform the Installation <a class="header-anchor" href="#phase-3-perform-the-installation" aria-label="Permalink to &quot;Phase 3: Perform the Installation&quot;">​</a></h3><ol><li>Insert the prepared USB drive into the target computer.</li><li>Turn on the PC and access the <strong>Boot Menu</strong> (typically via <code>F12</code>, <code>F11</code>, <code>F8</code>, or <code>F2</code> depending on the motherboard).</li><li>Select your USB drive to boot.</li><li><strong>Hands-Off Setup</strong>: Once the installer boots, it will read <code>autounattend.xml</code>. The partitioning, license agreement, edition selection, and account setup steps are automated. The computer will reboot several times and drop you directly onto a fully-configured, debloated desktop logged in as <code>Admin</code>.</li></ol><hr><h2 id="⚠️-essential-warning" tabindex="-1">⚠️ Essential Warning <a class="header-anchor" href="#⚠️-essential-warning" aria-label="Permalink to &quot;⚠️ Essential Warning&quot;">​</a></h2><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>This unattended setup applies extremely aggressive modifications. It completely disables Windows Defender, SmartScreen, and System Restore, and debloats many Microsoft systems.</p><p><em>Do NOT use this XML on high-security enterprise workstations, database servers, or systems containing sensitive financial datasets without implementing alternative protection strategies.</em></p></div>`,31)])])}const g=t(n,[["render",i]]);export{h as __pageData,g as default};
